package controller;
import koneksi.Koneksi;import java.io.*;import java.sql.*;import java.time.LocalDate;import java.util.*;import com.itextpdf.kernel.pdf.*;import com.itextpdf.layout.*;import com.itextpdf.layout.element.*;
public class TabunganController{public double saldo(int siswa)throws SQLException{try(PreparedStatement ps=Koneksi.getConnection().prepareStatement("SELECT COALESCE(MAX(saldo_akhir),0) FROM tabungan WHERE id_siswa=?")){ps.setInt(1,siswa);try(ResultSet r=ps.executeQuery()){return r.next()?r.getDouble(1):0;}}}public boolean mutasi(int siswa,String jenis,double nominal,String ket)throws SQLException{double s=saldo(siswa);double akhir="TARIK".equals(jenis)?s-nominal:s+nominal;if(akhir<0)throw new SQLException("Saldo tabungan tidak boleh minus");try(PreparedStatement ps=Koneksi.getConnection().prepareStatement("INSERT INTO tabungan(id_siswa,tanggal,jenis,nominal,saldo_akhir,keterangan) VALUES(?,?,?,?,?,?)")){ps.setInt(1,siswa);ps.setDate(2,java.sql.Date.valueOf(LocalDate.now()));ps.setString(3,jenis);ps.setDouble(4,nominal);ps.setDouble(5,akhir);ps.setString(6,ket);return ps.executeUpdate()>0;}}public List<Object[]> riwayat(int siswa)throws SQLException{List<Object[]>l=new ArrayList<>();try(PreparedStatement ps=Koneksi.getConnection().prepareStatement("SELECT tanggal,jenis,nominal,saldo_akhir,keterangan FROM tabungan WHERE id_siswa=? ORDER BY tanggal,id_tabungan")){ps.setInt(1,siswa);try(ResultSet r=ps.executeQuery()){while(r.next())l.add(new Object[]{r.getDate(1),r.getString(2),r.getDouble(3),r.getDouble(4),r.getString(5)});}}return l;}public void cetakRekapPdf(File f,int siswa)throws Exception{try(PdfWriter w=new PdfWriter(f);PdfDocument pdf=new PdfDocument(w);Document d=new Document(pdf)){d.add(new Paragraph("Rekap Tabungan Siswa #"+siswa).setBold().setFontSize(18));for(Object[] r:riwayat(siswa))d.add(new Paragraph(Arrays.toString(r)));}}}
